composeOverride:
# Generated by McHarbor App Store
services:
  {{serviceName}}:
    image: {{image}}
    container_name: {{containerName}}
    restart: unless-stopped
    depends_on:
      - {{serviceName}}-db
{{ports}}
    volumes:
      - {{env.WORDPRESS_DATA_PATH}}:/var/www/html
    environment:
      WORDPRESS_DB_HOST: {{serviceName}}-db:3306
      WORDPRESS_DB_NAME: {{env.WORDPRESS_DB_NAME}}
      WORDPRESS_DB_USER: {{env.WORDPRESS_DB_USER}}
      WORDPRESS_DB_PASSWORD: {{env.WORDPRESS_DB_PASSWORD}}
  {{serviceName}}-db:
    image: mariadb:11
    container_name: {{containerName}}-db
    restart: unless-stopped
    volumes:
      - {{env.WORDPRESS_DB_PATH}}:/var/lib/mysql
    environment:
      MARIADB_DATABASE: {{env.WORDPRESS_DB_NAME}}
      MARIADB_USER: {{env.WORDPRESS_DB_USER}}
      MARIADB_PASSWORD: {{env.WORDPRESS_DB_PASSWORD}}
      MARIADB_ROOT_PASSWORD: {{env.WORDPRESS_DB_ROOT_PASSWORD}}
